let isLocal = global.get('localNetwork') || false;

msg.payload = {
    ip: msg.req.ip,
    localNetwork: isLocal
};
return msg;

let blocked = msg.req.query.blocked === 'true';

msg.payload = {
    groups: blocked
        ? { disable: ["59b84ef62cd6fe8a"] }
        : { enable: ["59b84ef62cd6fe8a"] }
};
return msg;

let success = msg.payload.includes('TTL=');
global.set('localNetwork', success);
msg.payload = 'Local network: ' + success;
return msg;

//node.warn("STATUS INPUT: " + msg.topic);

// OFFLINE case
if (msg.topic === "__offline__" || msg.topic === "offline") {
    let offline = {
        text: "OFFLINE",
        style: "color:red",
        code: "0"
    };
    flow.set("lastStatus", offline);

    msg.payload = `<div style="${offline.style}">${offline.text}</div>`;
    return msg;
}

// FLASH case
if (msg.topic === "flashTrigger") {
    let st = flow.get("lastStatus");
    if (!st) return null;

    if (msg.payload === "__flash__") {
        // dot ON
        msg.payload = `<div><span style="color:lime;">●</span> <span style="${st.style}">${st.text}</span></div>`;
    } else {
        // dot OFF
        msg.payload = `<div style="${st.style}">${st.text}</div>`;
    }
    return msg;
}


// Ignore everything except real status messages
if (msg.topic !== "globe/status") {
    return null;
}

// NORMAL STATUS case
let code = ("" + msg.payload).trim();

let statusMap = {
    "0":  { text: "wait for globe position sync", style: "color:yellow;" }, 
    "1":  { text: "free running", style: "color:yellow;" },             // not used
    "2":  { text: "measuring rotation speed", style: "color:yellow" }, 
    "3":  { text: "rotation not locked to clock", style: "color:yellow" }, 
    "4":  { text: "rotation locked to clock", style: "color:#40ff40" }, // green
    "5":  { text: "rotation is OFF", style: "color:#40ff40;" },         // green
    "6":  { text: "globe is not floating", style: "color:yellow;font-weight:bold;" }, 
    "17": { text: "Error: dropped globe", style: "color:red;font-weight:bold;background:#ffcccc;" }, 
    "18": { text: "Error: sticky globe", style: "color:red;font-weight:bold;background:#ffcccc;" }, 
    "19": { text: "Error: overload", style: "color:red;font-weight:bold;background:#ffcccc;" }, 
    "20": { text: "Error: temp too high", style: "color:red;font-weight:bold;background:#ffcccc;" }
};

let mapped = statusMap[code];

if (!mapped) {
    mapped = { text: "OFFLINE", style: "color:red", code: "0" };
}

mapped.code = code;
flow.set("lastStatus", mapped);

msg.payload = `<div style="${mapped.style || ""}">${mapped.text}</div>`;
return msg;

let data = msg.payload;

let actRotTimeMsg = { payload: data.actRotTime} ;
let rotSyncErrorMsg = { payload: data.rotSyncError};
let greenwichLagMsg = { payload: data.greenwichLag};

// Return all three
return [actRotTimeMsg, rotSyncErrorMsg, greenwichLagMsg];

flow.set("lastUpdate", new Date());
flow.set("flash", true);
return null;

let last = flow.get("lastUpdate");
if (!last) return null;

last = new Date(last);
let current = new Date();

let diffSeconds = Math.floor((current.getTime() - last.getTime()) / 1000);

// Build the base text
let text;

if (diffSeconds < 60) {
    text = diffSeconds + " seconds ago";
} else {
    let sameDay =
        current.getFullYear() === last.getFullYear() &&
        current.getMonth() === last.getMonth() &&
        current.getDate() === last.getDate();

    if (sameDay) {
        text = last.toLocaleTimeString();
    } else {
        text = last.toLocaleString();
    }
}

// Check if a flash is requested
let flash = flow.get("flash");

if (flash) {
    // Flash ON (brief highlight)
    msg.payload = "<span style='color:lime;font-weight:bold;'>" + text + "</span>";

    // Clear flash flag immediately
    flow.set("flash", false);

    // Schedule a reset after 200 ms
    setTimeout(() => {
        node.send({ payload: text });
    }, 100);

    return msg;
}

// Normal display
msg.payload = text;
return msg;

flow.set("statusFlash", true);

// Flash ON
node.send({ topic: "flashTrigger", payload: "__flash__" });

// Flash OFF after 300 ms
setTimeout(() => {
    node.send({ topic: "flashTrigger", payload: "__noflash__" });
}, 300);

return null;

const timeoutMs = 20000;  // 20 seconds

let lastSeen = flow.get("lastSeen");
if (!lastSeen) {
    return null;   // no data yet
}

let now = Date.now();
let delta = now - lastSeen;

if (delta > timeoutMs) {
    return {
        topic: "offline",
        payload: "__offline__"
    };
}

return null;

let data = msg.payload;

let setRotTimeMsg = { payload: data.setRotTime } ;
let setLedEffectMsg = { payload: data.setLedEffect};
let setLedEffectSpeedMsg = { payload: data.setLedEffectSpeed};

// Return all three
return [setRotTimeMsg, setLedEffectMsg, setLedEffectSpeedMsg];

const gain_center = 0.7;
const gain_incr = 0.0125;

const dif_center = 23;
const dif_incr = 0.125;

const int_center = 10;
const int_incr = 0.5;

const center_index = 16;        // range: 0-32

let data = msg.payload;

let setGainAdjustMsg = {
    payload: gain_center + (data.setGainAdjust - center_index) * gain_incr
};

let setDifTimeAdjustMsg = {
    payload: dif_center + (data.setDifTimeAdjust - center_index) * dif_incr
};

let setIntTimeAdjustMsg = {
    payload: int_center + (data.setIntTimeAdjust - center_index) * int_incr
};

// Return all three outputs 
return [setGainAdjustMsg, setDifTimeAdjustMsg, setIntTimeAdjustMsg];

let rot   = flow.get("setRotTime");
let eff   = flow.get("setLedEffect");
let speed = flow.get("setLedEffectSpeed");

msg.payload = {
    setRotTime: Number(rot),
    setLedEffect: Number(eff),
    setLedEffectSpeed: Number(speed)
};

return msg;

// Keys used in flow context
const keys = [
    "setRotTime",
    "setLedEffect",
    "setLedEffectSpeed"
];

// Read values from context
let values = keys.map(k => {
    let v = flow.get(k);
    return (v === undefined) ? "" : v;   // preserve 0, replace only undefined
});

// Send to the three dropdowns
return [
    { payload: values[0] },
    { payload: values[1] },
    { payload: values[2] }
];

// ----- Gain parameters -----
const minVal = 0.5;         // minimim value
const incr   = 0.0125;      // step size
const minIdx = 0;           // minimum step
const maxIdx = 32;          // maximum step

// Incoming GAIN VALUE from spinner (0.5 ... 0.9)
let gain = Number(msg.payload);
let idx = Math.round((gain - minVal)/ incr);
let snappedGain = minVal + idx * incr;

// Clamp index
idx = Math.max(minIdx, Math.min(maxIdx, idx));

// Store for restore logic
flow.set("setGainAdjust", idx);
flow.set("gain_value", snappedGain);

// Output ONLY the index
return { payload: idx };

// PID differentiation time constant (mS) parameters
const minVal = 21       // minimum value
const incr   = 0.125;   // step size
const minIdx = 0;       // minimum step
const maxIdx = 32;      // maximum step

// Incoming DIFF.TIME CONST. VALUE from spinner (0.5 ... 0.9)
let difTimeConst = Number(msg.payload);

// Snap the t.c. to the nearest valid step
let snappedDifTimeConst = minVal + Math.round((difTimeConst - minVal) / incr) * incr;

// Compute index from snapped dif.time constant
let idx = Math.round((snappedDifTimeConst - minVal) / incr);

// Clamp index
idx = Math.max(minIdx, Math.min(maxIdx, idx));

// Store for restore logic
flow.set("setDifTimeAdjust", idx);
flow.set("difTime_value", snappedDifTimeConst);

// Output ONLY the index
return { payload: idx };

// PID integration time constant (second) parameters
const minVal = 2;       // minimum value 
const incr   = 0.5;     // step size
const minIdx   = 0;     // minimum step
const maxIdx   = 32;    // maximum step

// Incoming INT.TIME CONST. VALUE from spinner (0.5 ... 0.9)
let intTimeConst = Number(msg.payload);

// Snap the t.c. to the nearest valid step
let snappedIntTimeConst = minVal + Math.round((intTimeConst - minVal) / incr) * incr;

// Compute index from snapped int.time constant
let idx = Math.round((snappedIntTimeConst - minVal) / incr);

// Clamp index
idx = Math.max(minIdx, Math.min(maxIdx, idx));

// Store for restore logic
flow.set("setIntTimeAdjust", idx);
flow.set("intTime_value", snappedIntTimeConst);

// Output ONLY the index
return { payload: idx };

const keys = [
    "gain_value",
    "difTime_value",
    "intTime_value"
];

// Read values from context
let values = keys.map(k => {
    let v = flow.get(k);
    return (v === undefined) ? "" : v;   // preserve 0, replace only undefined
});

// Send to the three dropdowns
return [
    { payload: values[0] },
    { payload: values[1] },
    { payload: values[2] }
];

flow.set("setVertPosIndex", msg.payload);
flow.set("vertPosIndex_value", msg.payload);
return msg;

let vertPos = flow.get("setVertPosIndex");
let isLocal = global.get("localNetwork");

msg.payload = {
    setVertPosSetpoint: Number(vertPos),
    token: isLocal ? "gl0be_L0cal_9x" : ""
};

return msg;

let v = flow.get("vertPosIndex_value");
msg.payload = (v === undefined) ? "" : v;
return {payload: msg.payload};

let gain   = flow.get("setGainAdjust");
let diffTC = flow.get("setDifTimeAdjust");
let intTc  = flow.get("setIntTimeAdjust");
let isLocal = global.get("localNetwork");

msg.payload = {
    setGainAdjust: Number(gain),
    setDifTimeAdjust: Number(diffTC),
    setIntTimeAdjust: Number(intTc),
    token: isLocal ? "gl0be_L0cal_9x" : ""
};

return msg;

let v = flow.get("coilPhaseAdjust_value");
msg.payload = (v === undefined) ? "" : v;
return {payload: msg.payload};

let coilPhaseOut = msg.payload;
coilPhaseOut = Math.round(coilPhaseOut /2);
coilPhaseOut = Math.max(-90, Math.min(89, coilPhaseOut));  // Clamp 

let snappedValue = coilPhaseOut * 2;    // -90 to +89 degrees
coilPhaseOut += 90;                     // 0 to 179 degrees

flow.set("setCoilPhaseAdjust", coilPhaseOut);
flow.set("coilPhaseAdjust_value", snappedValue);

return {payload: coilPhaseOut};

let coilPhase = flow.get("setCoilPhaseAdjust");
let isLocal = global.get("localNetwork");

msg.payload = {
    setCoilPhaseAdjust: Number(coilPhase),
    token: isLocal ? "gl0be_L0cal_9x" : ""
};

return msg;

let coilPhaseMessage = {payload: msg.payLoad * 2};

if(coilPhaseMessage.payload >= 180) {coilPhaseMessage.payload = coilPhaseMessage.payload -360;}

return coilPhaseMessage.payload;

let data = msg.payload;

let temp = { payload: data.heatsinkTemp} ;
let magnetDuteCycle = { payload: data.magnetDutyCycle};
let isrDuration = { payload: data.ISRduration};
let load = {payload: data.load};
let vertPosError = {payload: data.vertPosError};
let TTTintegrationTerm = {payload: data.TTTintegrTerm};

// --- last message timestamp --- 
let now = new Date(); let timeString = now.toLocaleString(); // e.g. "3/2/2026, 16:51:12" 
let timestampMsg = { payload: timeString };

// Return all three
return [temp, magnetDuteCycle, isrDuration, load, vertPosError, TTTintegrationTerm, timestampMsg];
